mapper.insert:
insert into cotdl.tbl_piijob 
select jobid, TO_NUMBER(version)+1, jobname, system, policy_id, keymap_id, jobtype, runtype, calendar, time, cronval, confirmflag, status, 'CHECKOUT' as phase, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, enddate, regdate, SYSDATE as upddate, reguserid, upduserid
 from cotdl.tbl_piijob where jobid= #{jobid} and version= #{version, jdbcType=VARCHAR}

mapper.select:
 
		 
		select 
			jobid, version, jobname, system, policy_id, keymap_id, jobtype, runtype, calendar, time, cronval, confirmflag, status, phase, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, enddate, regdate, upddate, reguserid, upduserid
		from ( 
				select 
					 ROWNUM rn, jobid, version, jobname, system, policy_id, keymap_id, jobtype, runtype, calendar, time, cronval, confirmflag, status, phase, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, enddate, regdate, upddate, reguserid, upduserid
				from (
						select jobid, version, jobname, system, policy_id, keymap_id, jobtype, runtype, calendar, time, cronval, confirmflag, status, phase, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, to_char(enddate,'yyyy/mm/dd') as enddate, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piijob a
						 where version in (select max(to_number(version)) from cotdl.tbl_piijob where jobid = a.jobid)
						   and status != 'OLD' 
						 order by jobtype desc, system, policy_id, keymap_id
					 ) a
				where 
		
	    
		
						
							and upper(jobid) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and jobtype =#{search2, jdbcType=VARCHAR}
						
						
							and (job_owner_name1 like '%'||#{search3}||'%' or job_owner_name2 like '%'||#{search3}||'%' or job_owner_name3 like '%'||#{search3}||'%' or
							     job_owner_id1 like '%'||#{search3}||'%' or job_owner_id2 like '%'||#{search3}||'%' or job_owner_id3 like '%'||#{search3}||'%'
							)
						
						
							and system = #{search4, jdbcType=VARCHAR}
						
						
							and policy_id = #{search5, jdbcType=VARCHAR}
						
						
							and keymap_id like = #{search6, jdbcType=VARCHAR}
						
						
							and status = #{search7, jdbcType=VARCHAR}
						
						
							and runtype = #{search8, jdbcType=VARCHAR}
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by jobtype desc, system, policy_id, keymap_id
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by jobtype desc, system, policy_id, keymap_id
